    def default(self, obj: object) -> object:
        if isinstance(obj, np.ndarray):
            unique_values = []
            seen = {}
            for val in obj.tolist():
                key = str(val)
                if key not in seen:
                    seen[key] = len(unique_values)
                    unique_values.append(val)
