import flask
import numpy as np


class MyCustomJSONHandler(flask.json.provider.DefaultJSONProvider):
    def dumps(self, obj: object, **kwargs) -> str:
        import json
        import math

        def default_handler(x):
            if isinstance(x, np.ndarray):
                result = []
                seen = set()
                for val in x:
                    if val not in seen:
                        if isinstance(val, (np.floating, np.integer)):
                            result.append(float(val) if isinstance(val, np.floating) else int(val))
                        else:
                            result.append(val)
                        seen.add(val)
                return result
            if isinstance(x, (np.floating, np.integer)):
                return float(x) if isinstance(x, np.floating) else int(x)
            if isinstance(x, float) and (math.isnan(x) or math.isinf(x)):
                return str(x)
            raise TypeError(f"Object of type {type(x).__name__} is not JSON serializable")

        return json.dumps(obj, default=default_handler)


